/* ─── Helpers ─── */

export function getIdeaList(slug: string): IdeaList | undefined {
  return IDEA_LISTS.find((l) => l.slug === slug);
}

export function getAllIdeaSlugs(): string[] {
  return IDEA_LISTS.map((l) => l.slug);
}

export function getIdeaCollection(type: IdeaCollectionType): IdeaCollection | undefined {
  return IDEA_COLLECTIONS.find((c) => c.type === type);
}
